using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    // Category labels in the order ML.NET assigns slot indices
    public static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(data);

        // Evaluate on full dataset (small dataset — cross-validation is more meaningful)
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(data, pipeline, numberOfFolds: 3);

        _logger.LogInformation("=== Cross-Validation Results (3-fold) ===");
        foreach (var (result, i) in cvResults.Select((r, i) => (r, i)))
        {
            _logger.LogInformation("  Fold {Fold}: MacroAccuracy={MacroAccuracy:F4}, MicroAccuracy={MicroAccuracy:F4}, LogLoss={LogLoss:F4}",
                i + 1, result.Metrics.MacroAccuracy, result.Metrics.MicroAccuracy, result.Metrics.LogLossReduction);
        }

        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLossReduction);
        _logger.LogInformation("  Average:  MacroAccuracy={MacroAccuracy:F4}, MicroAccuracy={MicroAccuracy:F4}, LogLossReduction={LogLoss:F4}",
            avgMacro, avgMicro, avgLogLoss);

        // Also report per-class metrics from a full-data evaluation for diagnostics
        var predictions = model.Transform(data);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Full-Data Evaluation ===");
        _logger.LogInformation("  MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("  Confusion Matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

